import React from 'react';
import '../style/Home.css'; // Importando o CSS da pasta 'style'

const Home: React.FC = () => {
  return (
    <div className="container">
      <h1>Stock Flow</h1>
      <div className="button-container">
        <button id="vendas">Vendas</button>
        <button id="Estoque">Estoque</button>
      </div>
    </div>
  );
};

export default Home;
